import { parser } from "/repulse/lisp-lang/parser.js";
import { LRLanguage, LanguageSupport, indentNodeProp, foldNodeProp } from "goog:module$node_modules$$codemirror$language$dist$index_cjs";
import { autocompletion } from "goog:module$node_modules$$codemirror$autocomplete$dist$index_cjs";
import { repulseLispHighlight } from "/repulse/lisp-lang/highlight.js";
import { rainbowBrackets } from "/repulse/lisp-lang/rainbow.js";
import { builtinCompletions } from "/repulse/lisp-lang/completions.js";
import { defsCompletionSource } from "/repulse/lisp-lang/defs-completion.js";
import { keywordsCompletionSource } from "/repulse/lisp-lang/keywords-completion.js";
import { lispHoverTooltip } from "/repulse/lisp-lang/hover.js";
import { insertHelper } from "/repulse/lisp-lang/insert-helper.js";

const lispParser = parser.configure({
  props: [
    repulseLispHighlight,
    indentNodeProp.add({
      "List":   cx => cx.baseIndent + 2,
      "Vector": cx => cx.baseIndent + 2,
      "Map":    cx => cx.baseIndent + 2,
    }),
    foldNodeProp.add({
      "List":   node => ({ from: node.from + 1, to: node.to - 1 }),
      "Vector": node => ({ from: node.from + 1, to: node.to - 1 }),
    }),
  ],
});

export const lispLanguage = new LanguageSupport(
  LRLanguage.define({ parser: lispParser, languageData: { commentTokens: { line: ";" } } }),
  [
    rainbowBrackets,
    insertHelper,
    lispHoverTooltip,
    autocompletion({ override: [builtinCompletions, defsCompletionSource, keywordsCompletionSource] }),
  ]
);
